        <select class="admin-filter-select" name="field" aria-label="Pilih lapangan" onchange="this.form.submit()"><option value="">Semua Lapangan</option><?php foreach ($scheduleFields as $field): ?><option value="<?php echo e($field['id']); ?>" <?php echo $selectedField === $field['id'] ? 'selected' : ''; ?>><?php echo e($field['name']); ?></option><?php endforeach; ?></select>
